import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,e as t}from"./app-92bcc340.js";const e={},p=t(`<p>자바스크립트는 명령형, 함수형, 프로토타입 기반 객체지향 프로그래밍을 지원하는 멀티 패러다임 프로그래밍 언어다.<br> 클래스 기반 객체지향 프로그래밍 언어보다 효율적이며 더 강력한 객체지향 프로그래밍 능력을 지니고 있는 프로토타입 기반의 객체지향 프로그래밍언어다.</p><div class="hint-container info"><p class="hint-container-title">클래스(class)</p><p>ES6에서 클래스가 도입되었다. 하지만 ES6의 클래스가 기존 프로토타입 기반 객체지향 모델을 폐지하고 새로운 객체지향 모델을 제공하는 것은 아니다. 사실 클래스도 함수이며, 기존 프로토타입 기반 패턴의 문법적 설탕이라고 볼 수 있다.</p><p>클래스와 생성자 함수는 모두 프로토타입 기반의 인스턴스를 생성하지만 정확히 동일하게 동작하지는 않는다.<br> 클래스는 생성자 함수보다 엄격하며 클래스는 생성자 함수에서는 제공하지 않는 기능도 제공한다.</p><p>따라서 클래스를 프로토타입 기반 객체 생성패턴의 단순한 문법적 설탕으로 보기보다는 <strong>새로운 객체 생성 메커니즘</strong>으로 보는것이 좀 더 합당하다고 할 수 있다.</p><p>클래스에 대해서는 25장 &quot;클래스&quot;에서 자세히 살펴보자.</p></div><p>자바스크립트는 객체 기반의 프로그래밍 언어이며 <strong>자바스크립트를 이루고 있는 거의 &quot;모든 것&quot;이 객체다.</strong><br> 원시 타입의 값을 제외한 나머지 값들(함수, 배열, 정규 표현식 등)은 모두 객체다.</p><h2 id="_1-객체지향-프로그래밍" tabindex="-1"><a class="header-anchor" href="#_1-객체지향-프로그래밍" aria-hidden="true">#</a> 1. 객체지향 프로그래밍</h2><p>객체지향 프로그래밍은 프로그램을 명령어 또는 함수의 목록으로 보는 전통적인 명령형 프로그래밍의 절자지향적 관점에서 벗어나 여러 개의 독립적 단위, 즉 객체의 집합으로 프로그램을 표현하려는 프로그래밍 패러다임을 말한다.</p><p>객체지향 프로그래밍은 실세계의 실체(사물이나 개념)를 인식하는 철학적 사고를 프로그래밍에 접목하려는 시도에서 시작한다. 실체는 특징이나 성질을 나타내는 <strong>속성</strong>(attribute/property)을 가지고 있고, 이를 통해 실체를 인식하거나 구별할 수 있다.</p><p>예를 들어, 사람은 이름, 주소, 나이, 직업 등 다양한 속성을 갖는다.<br> 이때 &quot;이름이 아무개이고 성별은 여성이며 나이는 20세인 사람&quot;과 같이 속성을 구체적으로 표현하면 특정한 사람을 다른 사람과 구별하여 인식할 수 있다.</p><p>이러한 방식을 프로그래밍에 접목시켜보자. 사람에게는 다양한 속성이 있으나 우리가 구현하려는 프로그램에서는 사람의 &quot;이름&quot;과 &quot;주소&quot;라는 속성에만 관심이 있다고 가정하자. 이처럼 다양한 속성 중에서 프로그램에 필요한 속성만 간추려 내어 표현하는 것을 <strong>추상화</strong>(abstraction)라 한다.</p><p>&quot;이름&quot;과 &quot;주소&quot;라는 속성을 갖는 person이라는 객체를 자바스크립트로 표현하면 다음과 같다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 이름과 주소 속성을 갖는 객체</span>
<span class="token keyword">const</span> person <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&quot;Lee&quot;</span><span class="token punctuation">,</span>
  <span class="token literal-property property">address</span><span class="token operator">:</span> <span class="token string">&quot;Seoul&quot;</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>person<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// {name: &quot;Lee&quot;, address: &quot;Seoul&quot;}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>이때 프로그래머(subject, 주체)는 이름과 주소 속성으로 표현된 객체(object)인 person을 다른 객체와 구별하여 인식할 수 있다. 이처럼 <strong>속성을 통해 여러 개의 값을 하나의 단위로 구성한 복합적인 자료구조</strong>를 객체라 하며, 객체지향 프로그래밍은 독립적인 객체의 집합으로 프로그램을 표현하려는 프로그래밍 패러다임이다.</p><p>이번에는 원(Circle)이라는 개념을 객체로 만들어보자. 원에는 반지름이라는 속성이 있다. 이 반지름을 가지고 원의 지름, 둘레, 넓이를 구할 수 있다. 이때 반지름은 원의 상태를 나타내는 데이터이며 원의 지름, 둘레, 넓이를 구하는 것은 동작이다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> circle <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">radius</span><span class="token operator">:</span> <span class="token number">5</span><span class="token punctuation">,</span> <span class="token comment">// 반지름</span>

  <span class="token comment">// 원의 지름: 2r</span>
  <span class="token function">getDiameter</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token number">2</span> <span class="token operator">*</span> <span class="token keyword">this</span><span class="token punctuation">.</span>radius<span class="token punctuation">;</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>

  <span class="token comment">// 원의 둘레: 2πr</span>
  <span class="token function">getPerimeter</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token number">2</span> <span class="token operator">*</span> Math<span class="token punctuation">.</span><span class="token constant">PI</span> <span class="token operator">*</span> <span class="token keyword">this</span><span class="token punctuation">.</span>radius<span class="token punctuation">;</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>

  <span class="token comment">// 원의 넓이: πrr</span>
  <span class="token function">getArea</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> Math<span class="token punctuation">.</span><span class="token constant">PI</span> <span class="token operator">*</span> <span class="token keyword">this</span><span class="token punctuation">.</span>radius <span class="token operator">**</span> <span class="token number">2</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>circle<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">// {radius: 5, getDiameter: ƒ, getPerimeter: ƒ, getArea: ƒ}</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>circle<span class="token punctuation">.</span><span class="token function">getDiameter</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 10</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>circle<span class="token punctuation">.</span><span class="token function">getPerimeter</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 31.41592653589793</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>circle<span class="token punctuation">.</span><span class="token function">getArea</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 78.53981633974483</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>이처럼 객체지향 프로그래밍은 객체의 <strong>상태</strong>를 나타내는 데이터와 상태 데이터를 조작할 수 있는 <strong>동작</strong>을 하나의 논리적인 단위로 묶어 생각한다. 따라서 객체는 <strong>상태 데이터와 동작을 하나의 논리적인 단위로 묶은 복합적인 자료구조</strong>라고 할 수 있다. 이때 객체의 상태 데이터를 프로퍼티(property), 동작을 메서드(method)라 부른다.</p><h2 id="_2-상속과-프로토타입" tabindex="-1"><a class="header-anchor" href="#_2-상속과-프로토타입" aria-hidden="true">#</a> 2. 상속과 프로토타입</h2><p>상속(inheritance)은 객체지향 프로그래밍의 핵심 개념으로, 어떤 객체의 프로퍼티 또는 메서드를 다른 객체가 상속받아 그대로 사용할 수 있는 것을 말한다.<br> 자바스크립트는 프로토타입을 기반으로 상속을 구현하여 불필요한 중복을 제거한다. 중복을 제거하는 방법은 기존의 코드를 적극적으로 재사용하는 것이다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 생성자 함수</span>
<span class="token keyword">function</span> <span class="token function">Circle</span><span class="token punctuation">(</span><span class="token parameter">radius</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span>radius <span class="token operator">=</span> radius<span class="token punctuation">;</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span><span class="token function-variable function">getArea</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// Math.PI는 원주율을 나타내는 상수다.</span>
    <span class="token keyword">return</span> Math<span class="token punctuation">.</span><span class="token constant">PI</span> <span class="token operator">*</span> <span class="token keyword">this</span><span class="token punctuation">.</span>radius <span class="token operator">**</span> <span class="token number">2</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token comment">// 반지름이 1인 인스턴스 생성</span>
<span class="token keyword">const</span> circle1 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Circle</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">// 반지름이 2인 인스턴스 생성</span>
<span class="token keyword">const</span> circle2 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Circle</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// Circle 생성자 함수는 인스턴스를 생성할 때마다 동일한 동작을 하는</span>
<span class="token comment">// getArea 메서드를 중복 생성하고 모든 인스턴스가 중복 소유한다.</span>
<span class="token comment">// getArea 메서드는 하나만 생성하여 모든 인스턴스가 공유해서 사용하는 것이 바람직하다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>circle1<span class="token punctuation">.</span>getArea <span class="token operator">===</span> circle2<span class="token punctuation">.</span>getArea<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// false</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>circle1<span class="token punctuation">.</span><span class="token function">getArea</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 3.141592653589793</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>circle2<span class="token punctuation">.</span><span class="token function">getArea</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 12.566370614359172</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>Circle</code> 생성자 함수가 생성하는 모든 객체(인스턴스)는 <code>radius</code> 프로퍼티와 <code>getArea</code> 메서드를 갖는다.<br><code>radius</code> 프로퍼티 값은 일반적으로 인스턴스마다 다르다.<br> 하지만 <code>getArea</code> 메서드는 모든 인스턴스가 동일한 내용의 메서드를 사용하므로 단 하나만 생성하여 모든 인스턴스가 공유해서 사용하는 것이 바람직하다.<br><code>Circle</code> 생성자 함수는 인스턴스를 생성할 때마다 <code>getArea</code> 메서드를 중복 생성하고 모든 인스턴스가 중복 소유한다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/61aeff06-7651-449c-92df-929f689eccfe" alt="그림 19-1. 메서드 중복 생성" tabindex="0" loading="lazy"><figcaption>그림 19-1. 메서드 중복 생성</figcaption></figure><p>이처럼 동일한 생성자 함수에 의해 생성된 모든 인스턴스가 동일한 메서드를 중복 소유하는 것은 메모리를 불필요하게 낭비한다.<br> 상속을 통해 불필요한 중복을 제거해보자. <strong>자바스크립트는 프로토타입을 기반으로 상속을 구현한다.</strong></p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 생성자 함수</span>
<span class="token keyword">function</span> <span class="token function">Circle</span><span class="token punctuation">(</span><span class="token parameter">radius</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span>radius <span class="token operator">=</span> radius<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token comment">// Circle 생성자 함수가 생성한 모든 인스턴스가 getArea 메서드를</span>
<span class="token comment">// 공유해서 사용할 수 있도록 프로토타입에 추가한다.</span>
<span class="token comment">// 프로토타입은 Circle 생성자 함수의 prototype 프로퍼티에 바인딩되어 있다.</span>
<span class="token class-name">Circle</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function-variable function">getArea</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">return</span> Math<span class="token punctuation">.</span><span class="token constant">PI</span> <span class="token operator">*</span> <span class="token keyword">this</span><span class="token punctuation">.</span>radius <span class="token operator">**</span> <span class="token number">2</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// 인스턴스 생성</span>
<span class="token keyword">const</span> circle1 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Circle</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">const</span> circle2 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Circle</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// Circle 생성자 함수가 생성한 모든 인스턴스는 부모 객체의 역할을 하는</span>
<span class="token comment">// 프로토타입 Circle.prototype으로부터 getArea 메서드를 상속받는다.</span>
<span class="token comment">// 즉, Circle 생성자 함수가 생성하는 모든 인스턴스는 하나의 getArea 메서드를 공유한다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>circle1<span class="token punctuation">.</span>getArea <span class="token operator">===</span> circle2<span class="token punctuation">.</span>getArea<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>circle1<span class="token punctuation">.</span><span class="token function">getArea</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 3.141592653589793</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>circle2<span class="token punctuation">.</span><span class="token function">getArea</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 12.566370614359172</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/2e28ebe4-b7ae-404c-b232-0a89df2cfb74" alt="그림 19-2. 상속에 의한 메서드 공유" tabindex="0" loading="lazy"><figcaption>그림 19-2. 상속에 의한 메서드 공유</figcaption></figure><p><code>Circle</code> 생성자 함수가 생성한 모든 인스턴스는 자신의 프로토타입, 즉 상위(부모) 객체 역할을 하는 <code>Circle.prototype</code>의 모든 프로퍼티와 메서드를 상속받는다.</p><p><code>getArea</code> 메서드는 단 하나만 생성되어 프로토타입인 <code>Circle.prototype</code>의 메서드로 할당되어 있다. 따라서 <code>Circle</code> 생성자 함수가 생성하는 모든 인스턴스는 <code>getArea</code> 메서드를 상속받아 사용할 수 있따.<br> 즉, 자신의 상태를 나타내는 <code>radius</code> 프로퍼티만 개별적으로 소유하고 내용이 동일한 메서드는 상속을 통해 공유하여 사용하는 것이다.</p><p>상속은 코드의 재사용이란 관점에서 유용하다.</p><h2 id="_3-프로토타입-객체" tabindex="-1"><a class="header-anchor" href="#_3-프로토타입-객체" aria-hidden="true">#</a> 3. 프로토타입 객체</h2><p>프로토타입 객체란 객체지향 프로그래밍의 근간을 이루는 객체 간 상속을 구현하기 위해 사용된다.<br> 프로토타입은 어떤 객체의 상위(부모) 객체의 역할ㄹ을 하는 객체로서 다른 객체에 공유 프로퍼티를 제공한다.</p><p>모든 객체는 <code>[[Prototype]]</code>이라는 내부 슬롯을 가지며, 이 내부 슬롯의 값은 프로토타입의 참조다.<br><code>[[Prototype]]</code>에 저장되는 프로토타입은 객체 생성 방식에 의해 결정된다.<br> 즉, 객체가 생성될 때 객체 생성 방식에 따라 프로토타입이 결정되고 <code>[[Prototype]]</code>에 저장된다.</p><p>모든 객체는 하나의 프로토타입을 갖는다. 그리고 모든 프로토타입은 생성자 함수와 연결되어 있다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/acf4b8a2-7f4a-478e-9063-896927d4877d" alt="그림 19-3. 객체와 프로토타입과 생성자 함수는 서로 연결되어 있다." tabindex="0" loading="lazy"><figcaption>그림 19-3. 객체와 프로토타입과 생성자 함수는 서로 연결되어 있다.</figcaption></figure><h3 id="_3-1-proto-접근자-프로퍼티" tabindex="-1"><a class="header-anchor" href="#_3-1-proto-접근자-프로퍼티" aria-hidden="true">#</a> 3.1. <code>__proto__</code> 접근자 프로퍼티</h3><p>모든 객체는 <code>__proto__</code>접근자 프로퍼티를 통해 자신의 프로토타입, 즉 <code>[[Prototype]]</code>내부 슬롯에 간접적으로 접근할 수 있다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> person <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&quot;Lee&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/9f6d5f1c-f928-4daa-8f65-00112ce96040" alt="그림 19-4. 크롬 브라우저의 콘솔에서 출력한 객체의 프로퍼티" tabindex="0" loading="lazy"><figcaption>그림 19-4. 크롬 브라우저의 콘솔에서 출력한 객체의 프로퍼티</figcaption></figure><h4 id="proto-는-접근자-프로퍼티다" tabindex="-1"><a class="header-anchor" href="#proto-는-접근자-프로퍼티다" aria-hidden="true">#</a> <code>__proto__</code>는 접근자 프로퍼티다.</h4><p>내부 슬롯은 프로퍼티가 아니다. 따라서 원칙적으로 내부 슬롯과 내부 메서드에 직접적으로 접근하거나 호출할 수 있는 방법을 제공하지 않는다.<br><code>[[Prototype]]</code> 내부 슬롯에도 직접 접근할 수 없으며 <code>__proto__</code>접근자 프로퍼티를 통해 간접적으로 프로토타입에 접근할 수 있다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/05af1aa0-d2b2-4ec0-b998-abf761e1208c" alt="그림 19-5. 는 접근자 프로퍼티다." tabindex="0" loading="lazy"><figcaption>그림 19-5. <code>Object.Prototype.__proto__</code>는 접근자 프로퍼티다.</figcaption></figure><p><code>__proto__</code> 접근자 프로퍼티를 통해 새로운 프로토타입을 할당하면 <code>__proto__</code> 접근자 프로퍼티의 setter 함수인 <code>[[Set]]</code>이 호출된다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> obj <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">;</span>
<span class="token keyword">const</span> parent <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token literal-property property">x</span><span class="token operator">:</span> <span class="token number">1</span> <span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// getter 함수인 get **proto**가 호출되어 obj 객체의 프로토타입을 취득</span>
obj<span class="token punctuation">.</span><span class="token operator">**</span>proto<span class="token operator">**</span><span class="token punctuation">;</span>
<span class="token comment">// setter함수인 set **proto**가 호출되어 obj 객체의 프로토타입을 교체</span>
obj<span class="token punctuation">.</span><span class="token operator">**</span>proto<span class="token operator">**</span> <span class="token operator">=</span> parent<span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>obj<span class="token punctuation">.</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="proto-접근자-프로퍼티는-상속을-통해-사용된다" tabindex="-1"><a class="header-anchor" href="#proto-접근자-프로퍼티는-상속을-통해-사용된다" aria-hidden="true">#</a> <code>__proto__</code> 접근자 프로퍼티는 상속을 통해 사용된다.</h4><p><code>__proto__</code>접근자 프로퍼티는 객체가 직접 소유하는 프로퍼티가 아니라 <code>Object.prototype</code>의 프로퍼티다.<br> 모든 객체는 상속을 통해 <code>Object.prototype.__proto__</code> 접근자 프로퍼티를 사용할 수 있다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> person <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&quot;Lee&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// person 객체는 __proto__ 프로퍼티를 소유하지 않는다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>person<span class="token punctuation">.</span><span class="token function">hasOwnProperty</span><span class="token punctuation">(</span><span class="token string">&quot;__proto__&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// false</span>

<span class="token comment">// __proto__ 프로퍼티는 모든 객체의 프로토타입 객체인 Object.prototype의 접근자 프로퍼티다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>Object<span class="token punctuation">.</span><span class="token function">getOwnPropertyDescriptor</span><span class="token punctuation">(</span><span class="token class-name">Object</span><span class="token punctuation">.</span>prototype<span class="token punctuation">,</span> <span class="token string">&quot;__proto__&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">// {get: ƒ, set: ƒ, enumerable: false, configurable: true}</span>

<span class="token comment">// 모든 객체는 Object.prototype의 접근자 프로퍼티 __proto__를 상속받아 사용할 수 있다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">.</span>__proto__ <span class="token operator">===</span> <span class="token class-name">Object</span><span class="token punctuation">.</span>prototype<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container info"><p class="hint-container-title">Object.prototype</p><p>모든 객체는 프로토타입의 계층 구조인 프로토타입 체인에 묶여 있다. 자바스크립트 엔진은 객체의 프로퍼티에 접근하려고 할 때 해당 객체에 접근하려는 프로퍼티가 없다면 <code>__proto__</code> 접근자 프로퍼티가 가리키는 참조를 따라 자신의 부모 역할을 하는 프로토타입의 프로퍼티를 순차적으로 검색한다.</p><p>프로토타입 체인의 종점, 즉 프로토타입 체인의 최상위 객체는 Object.prototype이며, 이 객체의 프로퍼티와 메서드는 모든 객체에 상속된다.</p><p>이는 19.7절 &quot;프로토타입 체인&quot;에서 자세히 살펴보도록 하자.</p></div><h4 id="proto-접근자-프로퍼티를-통해-프로토타입에-접근하는-이유" tabindex="-1"><a class="header-anchor" href="#proto-접근자-프로퍼티를-통해-프로토타입에-접근하는-이유" aria-hidden="true">#</a> <code>__proto__</code> 접근자 프로퍼티를 통해 프로토타입에 접근하는 이유</h4><p><code>[[Prototype]]</code> 내부 슬롯의 값, 즉 프로토타입에 접근하기 위해 접근자 프로퍼티를 사용하는 이유는 상호 참조에 의해 프로토타입 체인이 생성되는 것을 방지하기 위해서다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> parent <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">;</span>
<span class="token keyword">const</span> child <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// child의 프로토타입을 parent로 설정</span>
child<span class="token punctuation">.</span>__proto__ <span class="token operator">=</span> parent<span class="token punctuation">;</span>
<span class="token comment">// parent의 프로토타입을 child로 설정</span>
parent<span class="token punctuation">.</span>__proto__ <span class="token operator">=</span> child<span class="token punctuation">;</span> <span class="token comment">// TypeError: Cyclic __proto__ value</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>위 예제에서는 parent 객체를 child 객체의 프로토타입으로 설정한 후, child 객체를 parent 객체의 프로토타입으로 설정했다.<br> 이러한 코드가 에러 없이 정상적으로 처리되면 서로가 자신의 프로토타입이 되는 비정상적인 프로토타입 체인이 만들어지기 때문에 <code>__proto__</code> 접근자 프로퍼티는 에러를 발생시킨다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/16c534b9-92f5-4c1e-94de-033bb7e9254f" alt="그림 19-6. 서로가 자신의 프로토타입이 되는 비정상적인 프로토타입 체인" tabindex="0" loading="lazy"><figcaption>그림 19-6. 서로가 자신의 프로토타입이 되는 비정상적인 프로토타입 체인</figcaption></figure><p>프로토타입 체인 방향은 단방향 링크드 리스크로 구현되어야 한다. 즉, 프로퍼티 검색 방향이 한쪽 방향으로 흘러가야한다. 하지만 위 그림과 같이 서로가 자신의 프로토타입이 되는 비정상적인 프로토타입 체인, 다시 말해 순환 참조(circular reference)하는 프로토타입 체인이 만들어지면 프로토타입 체인 종점이 존재하지 않기 때문에 프로토타입 체인에서 프로퍼티를 검색할 때 무한 루프에 빠진다.</p><h4 id="proto-접근자-프로퍼티를-코드-내에서-직접-사용하는-것은-권장하지-않는다" tabindex="-1"><a class="header-anchor" href="#proto-접근자-프로퍼티를-코드-내에서-직접-사용하는-것은-권장하지-않는다" aria-hidden="true">#</a> <code>__proto__</code> 접근자 프로퍼티를 코드 내에서 직접 사용하는 것은 권장하지 않는다.</h4><p>코드 내에서 <code>__proto__</code> 접근자 프로퍼티를 직접 사용하는 것은 권장하지 않는다. 모든 객체가 <code>__proto__</code> 접근자 프로퍼티를 사용할 수 있는 것은 아니기 때문이다. 나중에 살펴보겠지만 직접 상속을 통해 다음과 같이 <code>Object.prototype</code>을 상속받지 않는 객체를 생성할 수도 있기 때문에 <code>__proto__</code> 접근자 프로퍼티를 사용할 수 없는 경우가 있다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// obj는 프로토타입 체인의 종점이다. 따라서 Object.__proto__를 상속받을 수 없다.</span>
<span class="token keyword">const</span> obj <span class="token operator">=</span> Object<span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span><span class="token keyword">null</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// obj는 Object.__proto__를 상속받을 수 없다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>obj<span class="token punctuation">.</span>__proto__<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>

<span class="token comment">// 따라서 __proto__보다 Object.getPrototypeOf 메서드를 사용하는 편이 좋다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>Object<span class="token punctuation">.</span><span class="token function">getPrototypeOf</span><span class="token punctuation">(</span>obj<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// null</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>따라서 <code>__proto__</code> 접근자 프로퍼티 대신 프로토타입의 참조를 취득하고 싶은 경우에는 <code>Object.getPrototypeOf</code> 메서드를 사용하고, 프로토타입을 교체하고 싶은 경우에는 <code>Object.setPrototypeOf</code> 메서드를 사용할 것을 권장한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> obj <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">;</span>
<span class="token keyword">const</span> parent <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token literal-property property">x</span><span class="token operator">:</span> <span class="token number">1</span> <span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// obj 객체의 프로토타입을 취득</span>
Object<span class="token punctuation">.</span><span class="token function">getPrototypeOf</span><span class="token punctuation">(</span>obj<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// obj.__proto__;</span>
<span class="token comment">// obj 객체의 프로토타입을 교체</span>
Object<span class="token punctuation">.</span><span class="token function">setPrototypeOf</span><span class="token punctuation">(</span>obj<span class="token punctuation">,</span> parent<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// obj.__proto__ = parent;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>obj<span class="token punctuation">.</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>Object.getPrototypeOf</code> 메서드와 <code>Object.setPrototypeOf</code> 메서드는 <code>get Object.prototype.__proto__</code>와 <code>set Object.prototype.__proto__</code>의 처리 내용과 정확히 일치한다.</p><h3 id="_3-2-함수-객체의-prototype-프로퍼티" tabindex="-1"><a class="header-anchor" href="#_3-2-함수-객체의-prototype-프로퍼티" aria-hidden="true">#</a> 3.2. 함수 객체의 prototype 프로퍼티</h3><p>함수 객체만이 소유하는 prototype 프로퍼티는 생성자 함수가 생성할 인스턴스의 프로토타입을 가리킨다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 함수 객체는 prototype 프로퍼티를 소유한다.</span>
<span class="token punctuation">(</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">hasOwnProperty</span><span class="token punctuation">(</span><span class="token string">&quot;prototype&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; true</span>

<span class="token comment">// 일반 객체는 prototype 프로퍼티를 소유하지 않는다.</span>
<span class="token punctuation">(</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">hasOwnProperty</span><span class="token punctuation">(</span><span class="token string">&quot;prototype&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; false</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>prototype 프로퍼티는 생성자 함수가 생성할 객체(인스턴스)의 프로토타입을 가리킨다.<br> 따라서 생성자 함수로서 호출할 수 없는 함수, 즉 non-constructor인 화살표 함수와 ES6 메서드 축약 표현으로 정의한 메서드는 prototype 프로퍼티를 소유하지 않으며 프로토타입도 생성하지 않는다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 화살표 함수는 non-constructor다.</span>
<span class="token keyword">const</span> <span class="token function-variable function">Person</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token parameter">name</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span>name <span class="token operator">=</span> name<span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// non-constructor는 prototype 프로퍼티를 소유하지 않는다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>Person<span class="token punctuation">.</span><span class="token function">hasOwnProperty</span><span class="token punctuation">(</span><span class="token string">&quot;prototype&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// false</span>

<span class="token comment">// non-constructor는 프로토타입을 생성하지 않는다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token class-name">Person</span><span class="token punctuation">.</span>prototype<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>

<span class="token comment">// ES6의 메서드 축약 표현으로 정의한 메서드는 non-constructor다.</span>
<span class="token keyword">const</span> obj <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// non-constructor는 prototype 프로퍼티를 소유하지 않는다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>obj<span class="token punctuation">.</span>foo<span class="token punctuation">.</span><span class="token function">hasOwnProperty</span><span class="token punctuation">(</span><span class="token string">&quot;prototype&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// false</span>

<span class="token comment">// non-constructor는 프로토타입을 생성하지 않는다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>obj<span class="token punctuation">.</span>foo<span class="token punctuation">.</span>prototype<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>모든 객체가 가지고 있는 <code>__proto__</code> 접근자 프로퍼티와 함수 객체만이 가지고 있는 prototype 프로퍼티는 결국 동일한 프로토타입을 가리킨다.</p><table><thead><tr><th style="text-align:left;">구분</th><th style="text-align:left;">소유</th><th style="text-align:left;">사용 주체</th><th style="text-align:left;">사용 목적</th></tr></thead><tbody><tr><td style="text-align:left;"><code>__proto__</code> <br> 접근자 프로퍼티</td><td style="text-align:left;">모든 객체</td><td style="text-align:left;">모든 객체</td><td style="text-align:left;">객체가 자신의 포로토타입에 접근 <br>또는 교체하기 위해 사용</td></tr><tr><td style="text-align:left;">prototype <br> 프로퍼티</td><td style="text-align:left;">constructor</td><td style="text-align:left;">생성자 함수</td><td style="text-align:left;">생성자 함수가 자신이 생성할 객체의 <br>프로토타입을 할당하기 위해 사용</td></tr></tbody></table><p>생성자 함수로 객체를 생성한 후 <code>__proto__</code> 접근자 프로퍼티와 prototype 프로퍼티로 프로토타입 객체에 접근해보자.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 생성자 함수</span>
<span class="token keyword">function</span> <span class="token function">Person</span><span class="token punctuation">(</span><span class="token parameter">name</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span>name <span class="token operator">=</span> name<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">const</span> me <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Person</span><span class="token punctuation">(</span><span class="token string">&quot;Lee&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 결국 Person.prototype과 me.__proto__는 결국 동일한 프로토타입을 가리킨다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token class-name">Person</span><span class="token punctuation">.</span>prototype <span class="token operator">===</span> me<span class="token punctuation">.</span>__proto__<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/f0ebfda7-7532-4a04-bd79-19f1fc4bc9dc" alt="그림 19-7. 객체의 proto 접근자 프로퍼티와 함수 객체의 prototype 프로퍼티는 결구 동일한 프로토타입을 가리킨다." tabindex="0" loading="lazy"><figcaption>그림 19-7. 객체의 <strong>proto</strong> 접근자 프로퍼티와 함수 객체의 prototype 프로퍼티는 결구 동일한 프로토타입을 가리킨다.</figcaption></figure><h3 id="_3-3-프로토타입의-constructor-프로퍼티와-생성자-함수" tabindex="-1"><a class="header-anchor" href="#_3-3-프로토타입의-constructor-프로퍼티와-생성자-함수" aria-hidden="true">#</a> 3.3. 프로토타입의 constructor 프로퍼티와 생성자 함수</h3><p>모든 프로토타입은 constructor 프로퍼티를 갖는다. 이 constructor 프로퍼티는 prototype 프로퍼티로 자신을 참조하고 있는 생성자 함수를 가리킨다.<br> 이 연결은 생성자 함수가 생성될 때, 즉 함수 객체가 생성될 때 이뤄진다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 생성자 함수</span>
<span class="token keyword">function</span> <span class="token function">Person</span><span class="token punctuation">(</span><span class="token parameter">name</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span>name <span class="token operator">=</span> name<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">const</span> me <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Person</span><span class="token punctuation">(</span><span class="token string">&quot;Lee&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// me 객체의 생성자 함수는 Person이다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>me<span class="token punctuation">.</span>constructor <span class="token operator">===</span> Person<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/2a448388-1f1c-4da8-8531-46d46717308d" alt="그림 19-8. 프로토타입의 constructor 프로퍼티" tabindex="0" loading="lazy"><figcaption>그림 19-8. 프로토타입의 constructor 프로퍼티</figcaption></figure><p>위 예제에서 <code>Person</code> 생성자 함수는 <code>me</code> 객체를 생성했다. 이때 <code>me</code> 객체는 프로토타입의 constructor 프로퍼티를 통해 생성자 함수와 연결된다.<br><code>me</code> 객체에는 constructor 프로퍼티가 없지만 <code>me</code> 객체의 프로토타입인 <code>Person.prototype</code>에는 constructor 프로퍼티가 있다.<br> 따라서 <code>me</code> 객체는 프로토타입인 <code>Person.prototype</code>의 constructor 프로퍼티를 상속받아 사용할 수 있다.</p><h2 id="_4-리터럴-표기법에-의해-생성된-객체의-생성자-함수와-프로토타입" tabindex="-1"><a class="header-anchor" href="#_4-리터럴-표기법에-의해-생성된-객체의-생성자-함수와-프로토타입" aria-hidden="true">#</a> 4. 리터럴 표기법에 의해 생성된 객체의 생성자 함수와 프로토타입</h2><p>생성자 함수에 의해 생성된 인스턴스는 프로토타입의 constructor 프로퍼티에 의해 생성자 함수와 연결된다.<br> 이때 constructor 프로퍼티가 가리키는 생성자 함수는 인스턴스를 생성한 생성자 함수다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// obj 객체를 생성한 생성자 함수는 Object다.</span>
<span class="token keyword">const</span> obj <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Object</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>obj<span class="token punctuation">.</span>constructor <span class="token operator">===</span> Object<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>

<span class="token comment">// add 함수 객체를 생성한 생성자 함수는 Function이다.</span>
<span class="token keyword">const</span> add <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Function</span><span class="token punctuation">(</span><span class="token string">&quot;a&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;b&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;return a + b&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>add<span class="token punctuation">.</span>constructor <span class="token operator">===</span> Function<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>

<span class="token comment">// 생성자 함수</span>
<span class="token keyword">function</span> <span class="token function">Person</span><span class="token punctuation">(</span><span class="token parameter">name</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span>name <span class="token operator">=</span> name<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token comment">// me 객체를 생성한 생성자 함수는 Person이다.</span>
<span class="token keyword">const</span> me <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Person</span><span class="token punctuation">(</span><span class="token string">&quot;Lee&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>me<span class="token punctuation">.</span>constructor <span class="token operator">===</span> Person<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>하지만 리터럴 표기법에 의한 객체 생성 방식과 같이 명시적으로 new 연산자와 함께 생성자 함수를 호출하여 인스턴스를 생성하지 않는 객체 생성 방식도 있다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 객체 리터럴</span>
<span class="token keyword">const</span> obj <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// 함수 리터럴</span>
<span class="token keyword">const</span> <span class="token function-variable function">add</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token parameter">a<span class="token punctuation">,</span> b</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">return</span> a <span class="token operator">+</span> b<span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// 배열 리터럴</span>
<span class="token keyword">const</span> arr <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">;</span>

<span class="token comment">// 정규표현식 리터럴</span>
<span class="token keyword">const</span> regexp <span class="token operator">=</span> <span class="token regex"><span class="token regex-delimiter">/</span><span class="token regex-source language-regex">is</span><span class="token regex-delimiter">/</span><span class="token regex-flags">gi</span></span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>리터럴 표기법에 의해 생성된 객체도 물론 프로토타입이 존재한다. 하지만 리터럴 표기법에 의해 생성된 객체의 경우 프로토타입의 constructor 프로퍼티가 가리키는 생성자 함수가 반드시 객체를 생성한 생성자 함수라고 단정할 수 없다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// obj 객체는 Object 생성자 함수로 생성한 객체가 아니라 객체 리터럴로 생성했다.</span>
<span class="token keyword">const</span> obj <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// 하지만 obj 객체의 생성자 함수는 Object 생성자 함수다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>obj<span class="token punctuation">.</span>constructor <span class="token operator">===</span> Object<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>위 예제의 obj객체는 Object 생성자 함수로 생성한 객체가 아니라 객체 리터럴에 의해 생성된 객체다.<br> 하지만 obj 객체는 Object 생성자 함수와 constructor 프로퍼티로 연결되어 있다.<br> 그렇다면 객체 리터럴에 의해 생성된 객체는 사실 Object 생성자 함수로 생성되는 것은 아닐까?<br> ECMAScript 사양을 살펴보자. Object 생성자 함수는 다음과 같이 구현하도록 정의되어 있다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/483e444b-15c1-4186-a5e0-bb89955bbb08" alt="그림 19-9. Object 생성자 함수" tabindex="0" loading="lazy"><figcaption>그림 19-9. Object 생성자 함수</figcaption></figure><p>2에서 Object 생성자 함수에 인수를 전달하지 않거나 <code>undefined</code> 또는 <code>null</code>을 인수로 전달하면서 호출하면 내부적으로는 추상 연산 <code>OrdinaryObjectCreate</code>를 호출하여 <code>Object.prototype</code>을 프로토타입으로 갖는 빈 객체를 생성한다.</p><div class="hint-container info"><p class="hint-container-title">추상 연산(abstract operation)</p><p>추상 연산은 ECMAScript 사양에서 내부 동작의 구현 알고리즘을 표현한 것이다. ECMAScript 사양에서 설명을 위해 사용되는 함수와 유사한 의사코드라고 이해하자.</p></div><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 2. Object 생성자 함수에 의한 객체 생성</span>
<span class="token comment">// 인수가 전달되지 않았을 때 추상 연산 OrdinaryObjectCreate를 호출하여 빈 객체를 생성한다.</span>
<span class="token keyword">let</span> obj <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Object</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>obj<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// {}</span>

<span class="token comment">// 1. new.target이 undefined나 Object가 아닌 경우</span>
<span class="token comment">// 인스턴스 -&gt; Foo.prototype -&gt; Object.prototype 순으로 프로토타입 체인이 생성된다.</span>
<span class="token keyword">class</span> <span class="token class-name">Foo</span> <span class="token keyword">extends</span> <span class="token class-name">Object</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>
<span class="token keyword">new</span> <span class="token class-name">Foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// Foo {}</span>

<span class="token comment">// 3. 인수가 전달된 경우에는 인수를 객체로 변환한다.</span>
<span class="token comment">// Number 객체 생성</span>
obj <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Object</span><span class="token punctuation">(</span><span class="token number">123</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>obj<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// Number {123}</span>

<span class="token comment">// String  객체 생성</span>
obj <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Object</span><span class="token punctuation">(</span><span class="token string">&quot;123&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>obj<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// String {&quot;123&quot;}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>객체 리터럴이 평가될 때는 다음과 같이 추상 연산 <code>OrdinaryObjectCreate</code>를 호출하여 빈 객체를 생성하고 프로퍼티를 추가하도록 정의되어 있다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/20310990-944c-4dbd-86dd-645809f00e0f" alt="그림 19-10. 객체 리터럴의 평가" tabindex="0" loading="lazy"><figcaption>그림 19-10. 객체 리터럴의 평가</figcaption></figure><p>이처럼 Object 생성자 함수 호출과 객체 리터럴의 평가는 추상 연산 <code>OrdinaryObjectCreate</code>를 호출하여 빈 객체를 생성하는 점에서 동일하나 <code>new.target</code>의 확인이나 프로퍼티를 추가하는 처리 등 세부 내용은 다르다.</p><p>따라서 객체 리터럴에 의해 생성된 객체는 Object 생성자 함수가 생성한 객체가 아니다.</p><p>함수 객체의 경우 차이가 더 명확하다. 함수 선언문과 함수 표현식을 평가하여 함수 객체를 생성한 것은 Function 생성자 함수가 아니다. 하지만 constructor 프로퍼티를 통해 확인해보면 foo 생성자 함수는 Function 생성자 함수다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// foo 함수는 Function 생성자 함수로 생성한 함수 객체가 아니라 함수 선언문으로 생성했다.</span>
<span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>

<span class="token comment">// 하지만 constructor 프로퍼티를 통해 확인해보면 함수 foo의 생성자 함수는 Function 생성자 함수다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">.</span>constructor <span class="token operator">===</span> Function<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>프로토타입과 생성자 함수는 단독으로 존재할 수 없고 언제나 쌍(pair)으로 존재한다.<br> 리터럴 표기법(객체, 함수, 배열, 정규표현식)에 의해 생성된 객체는 생성자 함수에 의해 생성된 객체는 아니다. 하지만 큰 틀에서 생각해 보면 리터럴 표기법으로 생성한 객체도 생성자 함수로 생성한 객체의 본질적인 면에서 큰 차이는 없다.</p><p>프로토타입의 constructor 프로퍼티를 통해 연결되어 있는 생성자 함수를 리터럴 표기법으로 생성한 객체를 생성한 생성자 함수로 생각해도 크게 무리는 없다. 리터럴 표기법에 의해 생성된 객체의 생성자 함수와 프로토타입은 다음과 같다.</p><table><thead><tr><th style="text-align:left;">리터럴 표기법</th><th style="text-align:left;">생성자 함수</th><th style="text-align:left;">프로토타입</th></tr></thead><tbody><tr><td style="text-align:left;">객체</td><td style="text-align:left;">Object</td><td style="text-align:left;">Object.prototype</td></tr><tr><td style="text-align:left;">함수</td><td style="text-align:left;">Function</td><td style="text-align:left;">Function.prototype</td></tr><tr><td style="text-align:left;">배열</td><td style="text-align:left;">Array</td><td style="text-align:left;">Array.prototype</td></tr><tr><td style="text-align:left;">정규 표현식</td><td style="text-align:left;">RegExp</td><td style="text-align:left;">RegExp.prototype</td></tr></tbody></table><h2 id="_5-프로토타입의-생성-시점" tabindex="-1"><a class="header-anchor" href="#_5-프로토타입의-생성-시점" aria-hidden="true">#</a> 5. 프로토타입의 생성 시점</h2><p>리터럴 표기법에 의해 생성된 객체도 생성자 함수와 연결되는 것을 살펴보았다.<br> 객체는 리터럴 표기법 또는 생성자 함수에 의해 생성되므로 결국 모든 객체는 생성자 함수와 연결되어 있다.</p><div class="hint-container info"><p class="hint-container-title">Object.create 메서드와 클래스에 의한 객체 생성</p><p>아직 살펴보지 않았지만 Object.create 메서드와 클래스로 객체를 생성하는 방법도 있다.<br> Object.create 메서드와 클래스로 생성한 객체도 생성자 함수와 연결되어 있다. 이에 대해서는 19.11.1절 &quot;Object.create&quot;에 의한 직접 상속&quot;과 25장 &quot;클래스&quot;에서 살펴보도록 하자.</p></div><p><strong>프로토타입은 생성자 함수가 생성되는 시점에 더불어 생성된다.</strong><br> 생성자 함수는 사용자가 직접 정의한 사용자 정의 생성자 함수와 자바스크립트가 기본 제공하는 빌트인 생성자로 구분할 수 있다. 프로토타입 생성 시점에 대해 살펴보자.</p><h3 id="_5-1-사용자-정의-생성자-함수와-프로토타입-생성-시점" tabindex="-1"><a class="header-anchor" href="#_5-1-사용자-정의-생성자-함수와-프로토타입-생성-시점" aria-hidden="true">#</a> 5.1. 사용자 정의 생성자 함수와 프로토타입 생성 시점</h3><p>화살표 함수나 ES6의 메서드 축약 표현으로 정의하지 않고 일반 함수로 정의한 함수 객체는 new연산자와 함께 생성자 함수로서 호출할 수 있다.</p><p>생성자 함수로서 호출할 수 있는 함수. 즉 constructor는 함수 정의가 평가되어 함수 객체를 생성하는 시점에 프로토타입도 더불어 생성된다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 함수 정의(constructor)가 평가되어 함수 객체를 생성하는 시점에 프로토타입도 더불어 생성된다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token class-name">Person</span><span class="token punctuation">.</span>prototype<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// {constructor: ƒ}</span>

<span class="token comment">// 생성자 함수</span>
<span class="token keyword">function</span> <span class="token function">Person</span><span class="token punctuation">(</span><span class="token parameter">name</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span>name <span class="token operator">=</span> name<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>생성자 함수로서 호출할 수 없는 함수, 즉 non-constructor는 프로토타입이 생성되지 않는다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 화살표 함수는 non-constructor다.</span>
<span class="token keyword">const</span> <span class="token function-variable function">Person</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token parameter">name</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span>name <span class="token operator">=</span> name<span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// non-constructor는 프로토타입이 생성되지 않는다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token class-name">Person</span><span class="token punctuation">.</span>prototype<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>생성된 프로토타입은 Person 생성자 함수의 prototype 프로퍼티에 바인딩된다. Person 생성자 함수와 더불어 생성된 프로토타입의 내부를 살펴보자.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/030f2b84-54a0-4d8f-a473-237e6c31f514" alt="그림 19-11. 생성자 함수와 더불어 생성된 프로토타입" tabindex="0" loading="lazy"><figcaption>그림 19-11. 생성자 함수와 더불어 생성된 프로토타입</figcaption></figure><p>생성된 프로토타입은 오직 constructor 프로퍼티만 갖는 객체다. 프로토타입도 객체이고 모든 객체는 프로토타입을 가지므로 프로토타입도 자신의 프로토타입을 갖는다.<br> 생성된 프로토타입의 프로토타입은 <code>Object.prototype</code>이다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/fdb94348-4696-43eb-808c-5f095d5c7950" alt="그림 19-12. Person.prototype의 프로토타입" tabindex="0" loading="lazy"><figcaption>그림 19-12. Person.prototype의 프로토타입</figcaption></figure><h3 id="_5-2-빌트인-생성자-함수와-프로토타입-생성-시점" tabindex="-1"><a class="header-anchor" href="#_5-2-빌트인-생성자-함수와-프로토타입-생성-시점" aria-hidden="true">#</a> 5.2. 빌트인 생성자 함수와 프로토타입 생성 시점</h3><p>Object, String, Number, Function, Array 등과 같은 빌트인 생성자 함수도 일반 함수와 마찬가지로 빌트인 생성자 함수가 생성되는 시점에 프로토타입이 생성된다.<br> 모든 빌트인 생성자 함수는 전역 객체가 생성되는 시점에 생성된다.<br> 생성된 프로토타입은 빌트인 생성자 함수의 prototype 프로퍼티에 바인딩된다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/d619b6f5-b231-42c7-99ed-bb4239d0dd38" alt="그림 19-13. Object 생성자 함수와 프로토타입" tabindex="0" loading="lazy"><figcaption>그림 19-13. Object 생성자 함수와 프로토타입</figcaption></figure><div class="hint-container info"><p class="hint-container-title">전역 객체(global object)</p><p>전역 객체는 코드가 실행되기 이전 단계에 자바스크립트 엔진에 의해 생성되는 특수한 객체다.<br> 전역 객체는 클라이언트 사이드 환경(브라우저)에서 window, 서버 사이드 환경(Node.js)에서는 global 객체를 의미한다.</p><p>전역 객체는 표준 빌트인 객체(Object, String, Number, Function, Array ...)들과 같은 환경에 따른 호스트 객체(클라이언트 Web API 또는 Node.js의 호스트 API), 그리고 var 키워드로 선언한 전역 변수와 전역 함수를 프로퍼티로 갖는다. Math, Reflect,JSON을 제외한 표준 빌트인 객체는 모두 생성자 함수다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 전역 객체 window는 브라우저에 종속적이므로 아래 코드는 브라우저 환경에서 실행해야 한다.</span>
<span class="token comment">// 빌트인 객체인 Object는 전역 객체 window의 프로퍼티다.</span>
window<span class="token punctuation">.</span>Object <span class="token operator">===</span> Object<span class="token punctuation">;</span> <span class="token comment">// true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>표준 빌트인 객체인 Object도 전역 객체의 프로퍼티이며, 전역 객체가 생성되는 시점에 생성된다. 전역 객체와 표준 빌트인 객체에 대해서는 21장 &quot;빌트인 객체&quot;에서 자세히 살펴보자.</p></div><p>이처럼 객체가 생성되기 이전에 생성자 함수와 프로토타입은 이미 객체화되어 존재한다.<br> 이후 생성자 함수 또는 리터럴 표기법으로 객체를 생성하면 프로토타입은 생성된 객체의 <code>[[Prototype]]</code> 내부 슬롯에 할당된다. 이로써 생성된 객체는 프로토타입을 상속받는다.</p><h2 id="_6-객체-생성-방식과-프로토타입의-결정" tabindex="-1"><a class="header-anchor" href="#_6-객체-생성-방식과-프로토타입의-결정" aria-hidden="true">#</a> 6. 객체 생성 방식과 프로토타입의 결정</h2><p>객체는 다음과 같이 다양한 생성 방법이 있다.</p><ul><li>객체 리터럴</li><li>Object 생성자 함수</li><li>Object.create 메서드</li><li>클래스(ES6)</li></ul><p>이처럼 다양한 방식으로 생성된 모든 객체는 각 방식마다 세부적인 객체 생성 방식의 차이는 있으나 추상 연산 <code>OrdinaryObjectCreate</code>에 의해 생성된다는 공통점이 있다.</p><h3 id="_6-1-객체-리터럴에-의해-생성된-객체의-프로토타입" tabindex="-1"><a class="header-anchor" href="#_6-1-객체-리터럴에-의해-생성된-객체의-프로토타입" aria-hidden="true">#</a> 6.1. 객체 리터럴에 의해 생성된 객체의 프로토타입</h3><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> obj <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token literal-property property">x</span><span class="token operator">:</span> <span class="token number">1</span> <span class="token punctuation">}</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>위 객체 리터럴이 평가되면 추상 연산 <code>OrdinaryObjectCreate</code>에 의해 다음과 같이 Object 생성자 함수와 <code>Object.prototype</code>과 생성된 객체 사이에 연결이 만들어진다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/6216cb74-f125-479e-a377-174a07ee4093" alt="그림 19-14. 객체 리터럴에 의해 생성된 객체의 프로토타입" tabindex="0" loading="lazy"><figcaption>그림 19-14. 객체 리터럴에 의해 생성된 객체의 프로토타입</figcaption></figure><p>이처럼 객체 리터럴에 의해 생성된 obj 객체는 Object.prototype을 프로토타입으로 갖게되며, 이로써 Object.prototype을 상속받는다. obj 객체는 constructor 프로퍼티와 hasOwnProperty 메서드 등을 소유하지 않지만 자신의 프로토타입인 Object.prototype의 constructor 프로퍼티와 hasOwnProperty 메서드를 자신의 자산인 것처럼 자유롭게 사용할 수 있다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> obj <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token literal-property property">x</span><span class="token operator">:</span> <span class="token number">1</span> <span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// 객체 리터럴에 의해 생성된 obj 객체는 Object.prototype을 상속받는다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>obj<span class="token punctuation">.</span>constructor <span class="token operator">===</span> Object<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>obj<span class="token punctuation">.</span><span class="token function">hasOwnProperty</span><span class="token punctuation">(</span><span class="token string">&quot;x&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_6-2-object-생성자-함수에-의해-생성된-객체의-프로토타입" tabindex="-1"><a class="header-anchor" href="#_6-2-object-생성자-함수에-의해-생성된-객체의-프로토타입" aria-hidden="true">#</a> 6.2. Object 생성자 함수에 의해 생성된 객체의 프로토타입</h3><p>Object 생성자 함수를 인수 없이 호출하면 빈 객체가 생성된다. Object 생성자 함수를 호출하면 객체 리터럴과 마찬가지로 추상 연산 <code>OrdinaryObjectCreate</code>가 호출된다.<br> 이때 추상 연산 <code>OrdinaryObjectCreate</code>에 전달되는 프로토타입은 Object.prototype이다.<br> 즉, Object 생성자 함수에 의해 생성되는 객체의 프로토타입은 Object.prototype이다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> obj <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Object</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
obj<span class="token punctuation">.</span>x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>위 코드가 실행되면 추상 연산 <code>OrdinaryObjectCreate</code>에 의해 다음과 같이 Object 생성자 함수와 Object.prototype과 생성된 객체 사이에 연결이 만들어진다. 객체 리터럴에 의해 생성된 객체와 동일한 구조를 갖는 것을 알 수 있다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/6216cb74-f125-479e-a377-174a07ee4093" alt="그림 19-15. Object 생성자 함수에 의해 생성된 객체의 프로토타입" tabindex="0" loading="lazy"><figcaption>그림 19-15. Object 생성자 함수에 의해 생성된 객체의 프로토타입</figcaption></figure><p>이처럼 Object 생성자 함수에 의해 생성된 obj 객체는 Object.prototype을 프로토타입으로 갖게 되며 이로써 Object.prototype을 상속 받는다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> obj <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Object</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
obj<span class="token punctuation">.</span>x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>

<span class="token comment">// Object 생성자 함수에 의해 생성된 obj 객체는 Object.prototype을 상속받는다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>obj<span class="token punctuation">.</span>constructor <span class="token operator">===</span> Object<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>obj<span class="token punctuation">.</span><span class="token function">hasOwnProperty</span><span class="token punctuation">(</span><span class="token string">&quot;x&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>객체 리터럴과 Object 생성자 함수에 의한 객체 생성 방식의 차이는 프로퍼티를 추가하는 방식에 있다.<br> 객체 리터럴 방식은 객체 리터럴 내부에 프로퍼티를 추가하지만 Object 생성자 함수 방식은 일단 빈 객체를 생성한 이후 프로퍼티를 추가해야 한다.</p><h3 id="_6-3-생성자-함수에-의해-생성된-객체의-프로토타입" tabindex="-1"><a class="header-anchor" href="#_6-3-생성자-함수에-의해-생성된-객체의-프로토타입" aria-hidden="true">#</a> 6.3. 생성자 함수에 의해 생성된 객체의 프로토타입</h3><p>new 연산자와 함께 생성자 함수를 호출하여 인스턴스를 생성하면 다른 객체 생성 방식과 마찬가지로<br> 추상 연산 <code>OrdinaryObjectCreate</code>가 호출된다.<br> 이때 추상 연산 <code>OrdinaryObjectCreate</code>에 전달되는 프로토타입은 생성자 함수의 prototype 프로퍼티에 바인딩되어 있는 객체다. 즉, 생성자 함수에 의해 생성되는 객체의 프로토타입은 생성자 함수의 prototype 프로퍼티에 바인딩되어 있는 객체다.<br> 다음 예제를 살펴보자.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">Person</span><span class="token punctuation">(</span><span class="token parameter">name</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span>name <span class="token operator">=</span> name<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">const</span> me <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Person</span><span class="token punctuation">(</span><span class="token string">&quot;Lee&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>위 코드가 실행되면 추상 연산 <code>OrdinaryObjectCreate</code>에 의해 다음과 같이 생성자 함수와 생성자 함수의 prototype 프로퍼티에 바인딩되어 있는 객체와 생성된 객체 사이에 연결이 만들어진다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/fd92c072-408c-4932-81f9-54da16a89705" alt="그림 19-16. 생성자 함수에 의해 생성된 객체의 프로토타입" tabindex="0" loading="lazy"><figcaption>그림 19-16. 생성자 함수에 의해 생성된 객체의 프로토타입</figcaption></figure><p>표준 빌트인 객체인 Object 생성자 함수와 더불어 생성된 프로토타입 Object.prototype은 다양한 빌트인 메서드를 갖고 있다.<br> 하지만 사용자 정의 생성자 함수 Person과 더불어 생성된 프로토타입 Object.prototype의 프로퍼티는 constructor뿐이다.</p><p>프로토타입 Person.prototype에 프로퍼티를 추가하여 하위 객체가 상속받을 수 있도록 구현해보자.<br> 프로토타입은 객체다. 따라서 일반 객체와 같이 프로토타입에도 프로퍼티를 추가/삭제할 수 있다. 그리고 이렇게 추가된 추가/삭제한 프로퍼티는 프로토타입 체인에 즉각 반영된다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">Person</span><span class="token punctuation">(</span><span class="token parameter">name</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span>name <span class="token operator">=</span> name<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token comment">// 프로토타입 메서드</span>
<span class="token class-name">Person</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function-variable function">sayHello</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">Hi! My name is </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span><span class="token keyword">this</span><span class="token punctuation">.</span>name<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token keyword">const</span> me <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Person</span><span class="token punctuation">(</span><span class="token string">&quot;Lee&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">const</span> you <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Person</span><span class="token punctuation">(</span><span class="token string">&quot;Kim&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

me<span class="token punctuation">.</span><span class="token function">sayHello</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// Hi! My name is Lee</span>
you<span class="token punctuation">.</span><span class="token function">sayHello</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// Hi! My name is Kim</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Person 생성자 함수를 통해 생성된 모든 객체는 프로토타입에 추가된 <code>sayHello</code> 메서드를 상속받아 자신의 메서드처럼 사용할 수 있다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/648a01f5-2e17-421b-a010-6a8832ef9599" alt="그림 19-17. 프로토타입의 확장과 상속" tabindex="0" loading="lazy"><figcaption>그림 19-17. 프로토타입의 확장과 상속</figcaption></figure><h2 id="_7-프로토타입-체인" tabindex="-1"><a class="header-anchor" href="#_7-프로토타입-체인" aria-hidden="true">#</a> 7. 프로토타입 체인</h2><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">Person</span><span class="token punctuation">(</span><span class="token parameter">name</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span>name <span class="token operator">=</span> name<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token comment">// 프로토타입 메서드</span>
<span class="token class-name">Person</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function-variable function">sayHello</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">Hi! My name is </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span><span class="token keyword">this</span><span class="token punctuation">.</span>name<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token keyword">const</span> me <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Person</span><span class="token punctuation">(</span><span class="token string">&quot;Lee&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// hasOwnProperty는 Object.prototype의 메서드다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>me<span class="token punctuation">.</span><span class="token function">hasOwnProperty</span><span class="token punctuation">(</span><span class="token string">&quot;name&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Person 생성자 함수에 의해 생성된 me 객체는 Obejct.prototype의 메서드인 hasOwnProperty를 호출할 수 있다.<br> 이것은 me 객체가 Person.prototype뿐만 아니라 Object.prototype도 상속받았다는 것을 의미한다.<br> me 객체의 프로토타입은 Perosn.prototype이다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>Object<span class="token punctuation">.</span><span class="token function">getPrototypeOf</span><span class="token punctuation">(</span>me<span class="token punctuation">)</span> <span class="token operator">===</span> <span class="token class-name">Person</span><span class="token punctuation">.</span>prototype<span class="token punctuation">;</span> <span class="token comment">// -&gt; true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Person.prototype의 프로토타입은 Object.prototype이다. 프로토타입의 프로토타입은 언제나 Object.prototype이다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>Object<span class="token punctuation">.</span><span class="token function">getPrototypeOf</span><span class="token punctuation">(</span><span class="token class-name">Person</span><span class="token punctuation">.</span>prototype<span class="token punctuation">)</span> <span class="token operator">===</span> <span class="token class-name">Object</span><span class="token punctuation">.</span>prototype<span class="token punctuation">;</span> <span class="token comment">// -&gt; true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>따라서 위 예제를 그림으로 표현하면 다음과 같다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/95b6e198-e0cb-4f65-be2e-3992d0302fe0" alt="그림 19-18. 프로토타입 체인" tabindex="0" loading="lazy"><figcaption>그림 19-18. 프로토타입 체인</figcaption></figure><p>자바스크립트는 객체의 프로퍼티(메서드 포함)에 접근하려고 할 때 해당 객체에 접근하려는 프로퍼티가 없다면 <code>[[Prototype]]</code> 내부 슬롯의 참조를 따라 자신의 부모 역할을 하는 프로토타입의 프로퍼티를 순차적으로 검색한다. 이를 프로토타입 체인이라 한다. 프로토타입 체인은 자바스크립트가 객체지향 프로그래밍의 상속을 구현하는 메커니즘이다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// hasOwnProperty는 Object.prototype의 메서드다.</span>
<span class="token comment">// me 객체는 프로토타입 체인을 따라 hasOwnProperty 메서드를 검색하여 사용한다.</span>
me<span class="token punctuation">.</span><span class="token function">hasOwnProperty</span><span class="token punctuation">(</span><span class="token string">&quot;name&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>me.hasOwnProperty(&#39;name&#39;)과 같이 메서드를 호출하면 자바스크립트 엔진은 다음과 같은 과정을 거쳐 메스드를 검색한다.<br> 물론 프로퍼티를 참조하는 경우도 마찬가지다.</p><ol><li><p>먼저 hasOwnProperty 메서드를 호출한 me 객체에서 hasOwnProperty 메서드를 검색한다. me 객체에는 hasOwnProperty 메서드가 없으므로 프로토타입 체인을 따라, 다시 말해 <code>[[Prototype]]</code> 내부 슬롯에 바인딩되어 있는 프로토타입(위 예제의 경우 Person.prototype)으로 이동하여 hasOwnProperty 메서드를 검색한다.</p></li><li><p>Perosn.prototype에도 hasOwnProperty 메서드가 없으므로 프로토타입 체인을 따라, 1번과 같이 hasOwnProperty 메서드를 검색한다.</p></li><li><p>Object.prototype에 있는 hasOwnProperty 메서드가 존재한다.<br> 자바스크립트 엔진은 Object.prototype.hasOwnProperty메서드를 호출하고 해당 메서드의 this에는 me 객체가 바인딩 된다.</p></li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token class-name">Object</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function">hasOwnProperty</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>me<span class="token punctuation">,</span> <span class="token string">&#39;name&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="hint-container info"><p class="hint-container-title">call 메서드</p><p>call 메서드는 this로 사용할 객체를 전달하면서 함수를 호출한다. 이에 대해서는 22.2.4절 &quot;Function.prototype.apply/call/bind 메서드에 의한 간접 호출&quot;에서 자세히 살펴볼 것이다. 지금은 this로 사용할 me 객체를 전달하면서 Object.prototype.hasOwnProperty 메서드를 호출한다고 이해하자.</p></div><p>프로토타입 체인으 최상위에 위치한 객체는 언제나 Object.prototype이다. Object.prototype을 프로토타입 체인의 종점이라 한다. 종점의 프로토타입 <code>[[Prototype]]</code>내부 슬롯의 값은 null이다.</p><p>프로토타입 체인의 종점인 <code>Object.prototype</code>에서도 프로퍼티를 검색할 수 없는 경우 <code>undefined</code>를 반환한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>me<span class="token punctuation">.</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>이처럼 자바스크립트 엔진은 프로토타입 체인을 따라 프로퍼티/메서드를 검색한다. 다시 말해, 자바스크립트 엔진은 객체 간의 상속 관계로 이루어진 프로토타입의 계층적인 구조에서 객체의 프로퍼티를 검색한다. 따라서 <strong>프로토타입 체인은 상속과 프로퍼티 검색을 위한 메커니즘</strong>이라고 할 수 있다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>me<span class="token punctuation">.</span><span class="token function">hasOwnProperty</span><span class="token punctuation">(</span><span class="token string">&#39;name&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>위 예제의 경우, 먼저 스코프 체인에서 me 식별자를 검색한다. me 식별자는 전역에서 선언되었으므로 전역 스코프에서 검색된다. me 식별자를 검색한 다음, me 객체의 프로토타입 체인에서 hasOwnProperty 메서드를 검색한다. 이처럼 <strong>스코프 체인과 프로토타입 체인은 서로 연관없이 별도로 작동하는 것이 아니라 서로 협력하여 식별자와 프로퍼티를 검색하는 데 사용된다.</strong></p><h2 id="_8-오버라이딩과-프로퍼티-섀도잉" tabindex="-1"><a class="header-anchor" href="#_8-오버라이딩과-프로퍼티-섀도잉" aria-hidden="true">#</a> 8. 오버라이딩과 프로퍼티 섀도잉</h2><h2 id="_9-프로토타입의-교체" tabindex="-1"><a class="header-anchor" href="#_9-프로토타입의-교체" aria-hidden="true">#</a> 9. 프로토타입의 교체</h2><h3 id="_9-1-생성자-함수에-의한-프로토타입의-교체" tabindex="-1"><a class="header-anchor" href="#_9-1-생성자-함수에-의한-프로토타입의-교체" aria-hidden="true">#</a> 9.1. 생성자 함수에 의한 프로토타입의 교체</h3><h3 id="_9-2-인스턴스에-의한-프로토타입의-교체" tabindex="-1"><a class="header-anchor" href="#_9-2-인스턴스에-의한-프로토타입의-교체" aria-hidden="true">#</a> 9.2. 인스턴스에 의한 프로토타입의 교체</h3><h2 id="_10-instanceof-연산자" tabindex="-1"><a class="header-anchor" href="#_10-instanceof-연산자" aria-hidden="true">#</a> 10. instanceof 연산자</h2><h2 id="_11-직접-상속" tabindex="-1"><a class="header-anchor" href="#_11-직접-상속" aria-hidden="true">#</a> 11. 직접 상속</h2><h3 id="_11-1-object-create에-의한-직접-상속" tabindex="-1"><a class="header-anchor" href="#_11-1-object-create에-의한-직접-상속" aria-hidden="true">#</a> 11.1. Object.create에 의한 직접 상속</h3><h3 id="_11-2-객체-리터럴-내부에서-proto-에-의한-직접-상속" tabindex="-1"><a class="header-anchor" href="#_11-2-객체-리터럴-내부에서-proto-에-의한-직접-상속" aria-hidden="true">#</a> 11.2. 객체 리터럴 내부에서 <code>__proto__</code>에 의한 직접 상속</h3><h2 id="_12-정적-프로퍼티-메서드" tabindex="-1"><a class="header-anchor" href="#_12-정적-프로퍼티-메서드" aria-hidden="true">#</a> 12. 정적 프로퍼티/메서드</h2><h2 id="_13-프로퍼티-존재-확인" tabindex="-1"><a class="header-anchor" href="#_13-프로퍼티-존재-확인" aria-hidden="true">#</a> 13. 프로퍼티 존재 확인</h2><h3 id="_13-1-in-연산자" tabindex="-1"><a class="header-anchor" href="#_13-1-in-연산자" aria-hidden="true">#</a> 13.1 in 연산자</h3><h3 id="_13-2-object-prototype-hasownproperty-메서드" tabindex="-1"><a class="header-anchor" href="#_13-2-object-prototype-hasownproperty-메서드" aria-hidden="true">#</a> 13.2 Object.prototype.hasOwnProperty 메서드</h3><h2 id="_14-프로퍼티-열거" tabindex="-1"><a class="header-anchor" href="#_14-프로퍼티-열거" aria-hidden="true">#</a> 14. 프로퍼티 열거</h2><h3 id="_14-1-for-in-문" tabindex="-1"><a class="header-anchor" href="#_14-1-for-in-문" aria-hidden="true">#</a> 14.1. for ... in 문</h3><h3 id="_14-2-object-keys-values-entries-메서드" tabindex="-1"><a class="header-anchor" href="#_14-2-object-keys-values-entries-메서드" aria-hidden="true">#</a> 14.2. Object.keys/values/entries 메서드</h3>`,173),o=[p];function c(i,l){return s(),a("div",null,o)}const d=n(e,[["render",c],["__file","deepdive19.html.vue"]]);export{d as default};
